//! Schema-derived MetaSignal contract for privileged `spirit` policy.
//!
//! `schema/meta-signal.schema` is the source of truth. The checked-in file
//! under `src/schema/` is generated by `schema-rust-next` as a wire contract.
//! Runtime actors, sockets, storage, guardian calls, and daemon lowering live
//! in `spirit`.

#![forbid(unsafe_code)]

#[rustfmt::skip]
pub mod schema;

pub use schema::meta_signal::*;

pub type MetaRequest = Input;
pub type MetaReply = Output;

pub const META_SIGNAL_SCHEMA_SOURCE: &str = include_str!("../schema/meta-signal.schema");
pub const META_SIGNAL_RUST_SOURCE: &str = include_str!("schema/meta_signal.rs");
